export type Question = {
  text: string
  options: [string, string, string, string]
  correctIndex: number
}

export type Quiz = {
  id: string
  title: string
  questions: Question[]
  createdAt: string
}

export type QuizAttempt = {
  quizId: string
  answers: number[]
}

export type QuestionResult = {
  questionText: string
  selectedIndex: number
  correctIndex: number
  options: [string, string, string, string]
  correct: boolean
}

export type ScoreResult = {
  quizTitle: string
  total: number
  correct: number
  breakdown: QuestionResult[]
}

import type { Quiz } from './types'

const DATA_DIR = `${import.meta.dir}/data`
const QUIZZES_FILE = `${DATA_DIR}/quizzes.json`

const readQuizzes = async (): Promise<Quiz[]> => {
  const file = Bun.file(QUIZZES_FILE)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  return JSON.parse(text) as Quiz[]
}

const writeQuizzes = async (quizzes: Quiz[]): Promise<void> => {
  await Bun.write(QUIZZES_FILE, JSON.stringify(quizzes, null, 2))
}

export const getAllQuizzes = async (): Promise<Quiz[]> => {
  return readQuizzes()
}

export const getQuizById = async (id: string): Promise<Quiz | undefined> => {
  const quizzes = await readQuizzes()
  return quizzes.find((q) => q.id === id)
}

export const saveQuiz = async (quiz: Quiz): Promise<void> => {
  const quizzes = await readQuizzes()
  const existing = quizzes.findIndex((q) => q.id === quiz.id)
  if (existing >= 0) {
    quizzes[existing] = quiz
  } else {
    quizzes.push(quiz)
  }
  await writeQuizzes(quizzes)
}

export const deleteQuiz = async (id: string): Promise<void> => {
  const quizzes = await readQuizzes()
  const filtered = quizzes.filter((q) => q.id !== id)
  await writeQuizzes(filtered)
}

import type { Quiz, QuizAttempt, ScoreResult, QuestionResult } from './types'

export const scoreQuiz = (quiz: Quiz, attempt: QuizAttempt): ScoreResult => {
  const breakdown: QuestionResult[] = quiz.questions.map((question, i) => {
    const selectedIndex = attempt.answers[i] ?? -1
    return {
      questionText: question.text,
      selectedIndex,
      correctIndex: question.correctIndex,
      options: question.options,
      correct: selectedIndex === question.correctIndex,
    }
  })

  const correct = breakdown.filter((r) => r.correct).length

  return {
    quizTitle: quiz.title,
    total: quiz.questions.length,
    correct,
    breakdown,
  }
}

