    h('h1', { style: styles.heading }, 'Quiz Builder'),
    h('div', { style: { marginBottom: '20px' } },
      h('a', { href: '/create', style: styles.button }, '+ New Quiz'),
    ),
    quizzes.length === 0
      ? h('p', { style: styles.muted }, 'No quizzes yet. Create one to get started!')
      : h(Fragment, {},
          h('h2', { style: styles.subheading }, 'Your Quizzes'),
          ...quizzes.map((quiz) =>
            h('div', { style: styles.card },
              h('div', { style: { ...styles.flex, justifyContent: 'space-between' } },
                h('div', {},
                  h('strong', {}, quiz.title),
                  h('span', { style: { ...styles.muted, marginLeft: '8px' } },
                    `${quiz.questions.length} question${quiz.questions.length !== 1 ? 's' : ''}`,
                  ),
                ),
                h('div', { style: styles.flex },
                  h('a', {
                    href: `/take/${quiz.id}/0`,
                    style: styles.buttonSecondary,
                  }, 'Take'),
                  h('a', {
