export const renderTakeQuestion = (
  quiz: Quiz,
  questionIndex: number,
  answers: number[],
): string => {
  const question = quiz.questions[questionIndex]
  const total = quiz.questions.length
  const progress = ((questionIndex) / total) * 100
  const optionLetters = ['A', 'B', 'C', 'D'] as const
  const isLast = questionIndex === total - 1

  const template = h('div', { style: styles.page },
    h('h1', { style: styles.heading }, quiz.title),
    h('div', { style: styles.muted }, `Question ${questionIndex + 1} of ${total}`),
    h('div', { style: { ...styles.progressBar, marginTop: '8px' } },
      h('div', { style: { ...styles.progressFill, width: `${progress}%` } }),
    ),

    h('form', { method: 'POST', action: `/take/${quiz.id}/answer` },
      h('input', { type: 'hidden', name: 'questionIndex', value: String(questionIndex) }),
      h('input', { type: 'hidden', name: 'answers', value: JSON.stringify(answers) }),

      h('div', { style: styles.card },
        h('p', { style: { fontSize: '16px', fontWeight: '600', marginBottom: '16px' } }, question.text),
        h('div', { style: styles.radioGroup },
          ...question.options.map((option, i) =>
            h('label', { style: styles.radioLabel },
              h('input', {
                type: 'radio',
                name: 'selected',
                value: String(i),
                required: 'true',
              }),
              h('span', {}, `${optionLetters[i]}. ${option}`),
            ),
          ),
        ),
      ),

      h('button', { type: 'submit', style: styles.button },
        isLast ? 'Finish & See Results' : 'Next',
      ),
    ),
  )
  return template
}

export const renderScoreScreen = (result: ScoreResult): string => {
  const percentage = result.total > 0 ? Math.round((result.correct / result.total) * 100) : 0
  const optionLetters = ['A', 'B', 'C', 'D'] as const

  const template = h('div', { style: styles.page },
    h('h1', { style: styles.heading }, 'Quiz Results'),
    h('a', { href: '/', style: { ...styles.muted, display: 'block', marginBottom: '16px' } }, 'Back to home'),

    h('div', { style: styles.scoreBox },
      h('div', { style: styles.scoreBig }, `${result.correct}/${result.total}`),
      h('div', { style: { fontSize: '16px', color: '#666', marginTop: '4px' } },
        `${percentage}% — ${result.quizTitle}`,
      ),
    ),

    h('h2', { style: styles.subheading }, 'Question Breakdown'),
    ...result.breakdown.map((r, i) =>
      h('div', { style: { ...styles.card, borderLeft: `4px solid ${r.correct ? '#28a745' : '#dc3545'}` } },
        h('p', { style: { fontWeight: '600', marginBottom: '8px' } }, `${i + 1}. ${r.questionText}`),
        ...r.options.map((option, optIdx) => {
          const isSelected = optIdx === r.selectedIndex
          const isCorrect = optIdx === r.correctIndex
          let itemStyle: Record<string, string> = {
            padding: '4px 8px',
            borderRadius: '4px',
            fontSize: '14px',
            marginBottom: '2px',
          }
          if (isCorrect) {
            itemStyle = { ...itemStyle, ...styles.correct }
          } else if (isSelected && !isCorrect) {
            itemStyle = { ...itemStyle, ...styles.incorrect }
          }
          return h('div', { style: itemStyle },
            `${optionLetters[optIdx]}. ${option}`,
            isSelected && isCorrect ? ' (your answer)' : '',
            isSelected && !isCorrect ? ' (your answer)' : '',
            !isSelected && isCorrect ? ' (correct answer)' : '',
          )
        }),
      ),
    ),
  )
  return template
}

import { getAllQuizzes, getQuizById, saveQuiz, deleteQuiz } from './store'
import { scoreQuiz } from './scoring'
import {
  renderHome,
  renderCreateQuiz,
  renderTakeQuestion,
  renderScoreScreen,
} from './templates'
import type { Quiz, Question } from './types'

const html = (body: string): Response =>
  new Response(`<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Quiz Builder</title></head><body>${body}</body></html>`, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const redirect = (path: string): Response =>
  new Response(null, { status: 302, headers: { Location: path } })

const generateId = (): string =>
  crypto.randomUUID().slice(0, 8)

const parseForm = async (request: Request): Promise<Record<string, string>> => {
  const formData = await request.formData()
  const entries: Record<string, string> = {}
  formData.forEach((value, key) => {
    entries[key] = String(value)
  })
  return entries
}

// In-memory draft storage for quizzes being created
const drafts = new Map<string, { title: string; questions: Question[] }>()

export const handleRequest = async (request: Request): Promise<Response> => {
  const url = new URL(request.url)
  const path = url.pathname
  const method = request.method

  // Home — list quizzes
  if (path === '/' && method === 'GET') {
    const quizzes = await getAllQuizzes()
    return html(renderHome(quizzes))
  }

  // Create — show create form
  if (path === '/create' && method === 'GET') {
    const quizId = generateId()
    drafts.set(quizId, { title: '', questions: [] })
    return html(renderCreateQuiz(quizId, '', []))
  }

  // Create — set title
  if (path === '/create/title' && method === 'POST') {
    const form = await parseForm(request)
    const quizId = form.quizId
    const title = form.title?.trim() || 'Untitled Quiz'
    const draft = drafts.get(quizId) || { title: '', questions: [] }
    draft.title = title
    drafts.set(quizId, draft)
    return html(renderCreateQuiz(quizId, draft.title, draft.questions))
  }

  // Create — add question
  if (path === '/create/question' && method === 'POST') {
    const form = await parseForm(request)
    const quizId = form.quizId
    const draft = drafts.get(quizId)
    if (!draft) return redirect('/create')

    const question: Question = {
      text: form.text?.trim() || 'Untitled Question',
      options: [
        form.option0?.trim() || 'Option A',
        form.option1?.trim() || 'Option B',
        form.option2?.trim() || 'Option C',
        form.option3?.trim() || 'Option D',
      ],
      correctIndex: parseInt(form.correctIndex || '0', 10),
    }
    draft.questions.push(question)
    drafts.set(quizId, draft)
    return html(renderCreateQuiz(quizId, draft.title, draft.questions))
  }

  // Create — finish and save
  const finishMatch = path.match(/^\/create\/finish\/(.+)$/)
  if (finishMatch && method === 'GET') {
    const quizId = finishMatch[1]
    const draft = drafts.get(quizId)
    if (!draft || draft.questions.length === 0) return redirect('/create')

    const quiz: Quiz = {
      id: quizId,
      title: draft.title,
      questions: draft.questions,
      createdAt: new Date().toISOString(),
    }
    await saveQuiz(quiz)
    drafts.delete(quizId)
    return redirect('/')
  }

  // Delete quiz
  const deleteMatch = path.match(/^\/delete\/(.+)$/)
  if (deleteMatch) {
    await deleteQuiz(deleteMatch[1])
    return redirect('/')
  }

  // Take quiz — show question
  const takeMatch = path.match(/^\/take\/([^/]+)\/(\d+)$/)
  if (takeMatch && method === 'GET') {
    const quizId = takeMatch[1]
    const questionIndex = parseInt(takeMatch[2], 10)
    const quiz = await getQuizById(quizId)
    if (!quiz) return redirect('/')
    if (questionIndex >= quiz.questions.length) return redirect('/')

    const answersParam = url.searchParams.get('answers')
    const answers: number[] = answersParam ? JSON.parse(answersParam) : []
    return html(renderTakeQuestion(quiz, questionIndex, answers))
  }

  // Take quiz — submit answer
  const answerMatch = path.match(/^\/take\/([^/]+)\/answer$/)
  if (answerMatch && method === 'POST') {
    const quizId = answerMatch[1]
    const quiz = await getQuizById(quizId)
    if (!quiz) return redirect('/')

    const form = await parseForm(request)
    const questionIndex = parseInt(form.questionIndex || '0', 10)
    const selected = parseInt(form.selected || '0', 10)
    const answers: number[] = form.answers ? JSON.parse(form.answers) : []
    answers.push(selected)

    const nextIndex = questionIndex + 1
    if (nextIndex >= quiz.questions.length) {
      // Score and show results
      const result = scoreQuiz(quiz, { quizId, answers })
      return html(renderScoreScreen(result))
    }

    // Next question — pass answers via query string
    return redirect(`/take/${quizId}/${nextIndex}?answers=${encodeURIComponent(JSON.stringify(answers))}`)
  }

  return new Response('Not Found', { status: 404 })
}

import { handleRequest } from './routes'

const PORT = parseInt(process.env.PORT || '3000', 10)

const server = Bun.serve({
  port: PORT,
  fetch: handleRequest,
})

console.log(`Quiz Builder running at http://localhost:${server.port}`)
